let produtos = [];

async function carregarProdutos() {

  try {

    const resposta = await fetch('/api/produtos');

    produtos = await resposta.json();

    renderizarProdutos();

  } catch (erro) {

    console.error("Erro ao carregar produtos:", erro);

  }

}

const divProdutos = document.getElementById("produtos");
const totalSpan = document.getElementById("total");
const campoBusca = document.getElementById("campoBusca");

const carrinho = {};

function renderizarProdutos(filtro = "") {
  divProdutos.innerHTML = "";

  const grupos = {};

  produtos
    .filter(p => p.nome.toLowerCase().includes(filtro.toLowerCase()))
    .forEach(p => {
      if (!grupos[p.categoria]) grupos[p.categoria] = [];
      grupos[p.categoria].push(p);
    });

  for (let categoria in grupos) {
    const titulo = document.createElement("div");
    titulo.className = "categoria";
    titulo.innerText = categoria.toUpperCase();
    divProdutos.appendChild(titulo);

    grupos[categoria].forEach(p => {
      const qtd = carrinho[p.nome] || 0;

      const div = document.createElement("div");
      div.className = "produto";

      div.innerHTML = `
        <span class="nome">${p.nome}</span>

        <div class="controle">
          <button onclick="alterarQtd('${p.nome}', -1)">−</button>
          <input type="number" min="0" value="${qtd}" onchange="setarQtd('${p.nome}', this.value)">
          <button onclick="alterarQtd('${p.nome}', 1)">+</button>
        </div>

        <span class="preco">R$ ${p.preco.toFixed(2)}</span>
      `;

      divProdutos.appendChild(div);
    });
  }
}

function alterarQtd(nome, valor) {
  if (!carrinho[nome]) carrinho[nome] = 0;

  carrinho[nome] += valor;
  if (carrinho[nome] < 0) carrinho[nome] = 0;

  atualizarTotal();
  renderizarProdutos(campoBusca.value);
}

function setarQtd(nome, valor) {
  carrinho[nome] = Number(valor) || 0;
  atualizarTotal();
}

function atualizarTotal() {
  let total = 0;

  produtos.forEach(p => {
    const qtd = carrinho[p.nome] || 0;
    total += qtd * p.preco;
  });

  const desconto = Number(document.getElementById("desconto").value) || 0;

  if (desconto > 0) {
    total -= total * (desconto / 100);
  }

  totalSpan.innerText = total.toLocaleString("pt-BR", {
    minimumFractionDigits: 2
  });
}

campoBusca.addEventListener("input", e => {
  renderizarProdutos(e.target.value);
});

document.getElementById("desconto").addEventListener("input", atualizarTotal);

document.getElementById("btnGerar").addEventListener("click", () => {
  const nome = document.getElementById("nomeCliente").value || "";
  const desconto = Number(document.getElementById("desconto").value) || 0;

  let texto = `🧾 Orçamento Hydra\nCliente: ${nome}\n\n`;
  let total = 0;

  produtos.forEach(p => {
    const qtd = carrinho[p.nome] || 0;
    if (qtd > 0) {
      const subtotal = qtd * p.preco;
      total += subtotal;
      texto += `${p.nome} - ${qtd} un - R$ ${subtotal.toFixed(2)}\n`;
    }
  });

  if (desconto > 0) {
    const valorDesc = total * desconto / 100;
    total -= valorDesc;
    texto += `\nDesconto aplicado: -R$ ${valorDesc.toFixed(2)}\n`;
  }

  texto += `\nTOTAL: R$ ${total.toFixed(2)}`;

  document.getElementById("resultado").innerText = texto;
});

document.getElementById("btnCopiar").addEventListener("click", () => {
  navigator.clipboard.writeText(
    document.getElementById("resultado").innerText
  );
  alert("Orçamento copiado!");
});

carregarProdutos();

//pdf

// ===== PDF =====
document.getElementById("btnPDF").addEventListener("click", gerarPDF);

function gerarPDF() {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF("p", "mm", "a4"); // A4 vertical

  const nome = document.getElementById("nomeCliente").value || "Não informado";
  const desconto = Number(document.getElementById("desconto").value) || 0;

  let y = 20;
  let total = 0;

  // ===== CABEÇALHO =====
  doc.setFillColor(0, 102, 204); // azul da marca
  doc.rect(15, y - 5, 180, 25, "F"); // retângulo azul maior para caber logo

  doc.setFontSize(16);
  doc.setTextColor(255, 255, 255);
  doc.setFont("helvetica", "bold");
  doc.text("Hydra Piscinas - Orçamento", 20, y + 5);

  // ===== LOGO =====
  const logoBase64 = "data:image/jpeg;base64,"; // logo em Base64
  doc.addImage(logoBase64, "JPEG", 150, y - 5, 50, 40); // logo no canto superior direito

  y += 28; // pular espaço do cabeçalho

  // ===== DADOS DO CLIENTE =====
  doc.setFontSize(12);
  doc.setTextColor(0, 0, 0);
  doc.setFont("helvetica", "normal");
  doc.text(`CNPJ Hydra Piscinas 37.526.566/0001-61\nCliente: ${nome}`, 20, y);
  y += 10;

  // ===== TABELA DE PRODUTOS =====
  doc.setFont("helvetica", "bold");
  doc.text("Produto", 20, y);
  doc.text("Qtd", 140, y, { align: "right" });
  doc.text("Subtotal", 180, y, { align: "right" });
  y += 5;

  doc.setDrawColor(0);
  doc.setLineWidth(0.5);
  doc.line(20, y, 190, y);
  y += 5;

  doc.setFont("helvetica", "normal");

  produtos.forEach((p, index) => {
    const qtd = carrinho[p.nome] || 0;
    if (qtd > 0) {
      const subtotal = qtd * p.preco;
      total += subtotal;

      // linha alternada cinza claro
      if (index % 2 === 0) {
        doc.setFillColor(240, 240, 240);
        doc.rect(20, y - 4, 170, 7, "F");
      }

      doc.text(p.nome, 20, y);
      doc.text(`${qtd}`, 140, y, { align: "right" });
      doc.text(`R$ ${subtotal.toFixed(2)}`, 180, y, { align: "right" });
      y += 7;

      if (y > 270) {
        doc.addPage();
        y = 20;
      }
    }
  });

  // ===== DESCONTO =====
  if (desconto > 0) {
    const valorDesc = total * desconto / 100;
    total -= valorDesc;
    y += 5;
    doc.setFont("helvetica", "bold");
    doc.setTextColor(220, 0, 0);
    doc.text(`Desconto aplicado: -R$ ${valorDesc.toFixed(2)}`, 180, y, { align: "right" });
    y += 10;
  }

  // ===== TOTAL =====
  doc.setFontSize(14);
  doc.setTextColor(0, 0, 0);
  doc.setFont("helvetica", "bold");
  doc.text(`TOTAL: R$ ${total.toFixed(2)}`, 180, y, { align: "right" });

  // ===== GERAR PDF =====
  doc.save(`Orçamento-${nome.replace(/\s+/g, "_")}.pdf`);
}
